-- ESTUDIAR · Fase E-2 (INGLÉS) — tanda 2: B1+B2 (unidades 13-24), SOLO DATOS.
-- La tabla study_theory y las RPCs get_study_theory/submit_study_quiz ya viven
-- desde la mig 178 (tanda 1, A1+A2). Aquí solo se insertan los 12 temas B1+B2
-- (upsert idempotente por (course_id, unit_order) → la tanda 1 queda intacta).
-- SOLO inglés. NO toca motor FSRS, economía, gating, certificación ni los otros
-- 5 idiomas. El quiz sigue siendo FORMATIVO (jz_grade, sin XP/oro).


-- ── Datos (idempotente por (course_id, unit_order)) ────────────────────────
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 13, 'B1', 'Rutinas, hábitos y experiencias', 'Aprenderás a contar lo que ya hiciste hoy (just, already, yet), a describir hábitos del pasado que ya abandonaste (used to) y a decir cuánto tiempo llevas con una rutina (for / since).', '[{"heading": "Experiencias recientes: just, already, yet", "body": "Con el present perfect (have/has + participio) contamos experiencias sin decir cuándo. Just y already van entre have/has y el participio. Yet va al final, y solo en negativas y preguntas.", "bullets": ["just = hace un momento: I have just woken up.", "already = antes de lo esperado: She has already left.", "yet = todavía / ya, al final: Have you eaten yet?", "Negativa: I haven''t finished yet."]}, {"heading": "Hábitos del pasado: used to", "body": "Used to describe hábitos o estados del pasado que ya no son ciertos. Va siempre construido como used to + verbo en forma base (I used to smoke). En negativas y preguntas con did, pierde la -d: didn''t use to, did you use to?", "bullets": ["Afirmativa: I used to smoke, but I stopped.", "Negativa: He didn''t use to like coffee.", "Pregunta: Did you use to live here?", "Sirve para hábitos y también para estados."]}, {"heading": "Cuánto llevas: for y since", "body": "Con el present perfect, for mide la duración y since marca el punto de inicio. Ambos responden a How long...? y hablan de algo que empezó antes y sigue ahora.", "bullets": ["for + periodo: for two hours, for three years.", "since + momento concreto: since Monday, since 2019.", "Pregunta típica: How long have you worked here?", "Respuesta: I''ve worked here since March."]}]'::jsonb, '[{"en": "I have already finished the report.", "es": "Ya he terminado el informe.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/f1d67e81-e1b1-5d1f-b093-098162e1c49b.mp3"}, {"en": "My brother hasn''t called me yet.", "es": "Mi hermano todavía no me ha llamado.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/16a26b1e-be93-5189-bc4f-e8d740e3d4dc.mp3"}, {"en": "We used to walk to school every morning.", "es": "Antes íbamos caminando al colegio todas las mañanas.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/95298d75-e1ce-5214-ab0b-78736614724f.mp3"}, {"en": "She has played the guitar since she was ten.", "es": "Ella toca la guitarra desde que tenía diez años.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/0ef74dca-2a04-5b60-89cf-779786dab250.mp3"}]'::jsonb, '[{"title": "Poner yet en medio de la frase", "body": "Yet no se coloca como el español \"ya\". No digas I have yet finished. Lo correcto es I haven''t finished yet (negativa) o Have you finished yet? (pregunta). Para afirmativas usa already: I have already finished."}, {"title": "Confundir for con since", "body": "For mide cuánto tiempo; since dice desde cuándo. No digas I have lived here for 2019 ni I have lived here since three years. Correcto: for three years / since 2019."}, {"title": "Escribir used to en negativas y preguntas", "body": "Con did, el verbo vuelve a su forma base. No digas He didn''t used to work here. Lo correcto es He didn''t use to work here y Did you use to work here?"}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la frase correcta para decir \"Todavía no he desayunado\".", "options": ["I haven''t had breakfast yet.", "I have yet had breakfast.", "I haven''t had breakfast already."], "answer": "I haven''t had breakfast yet.", "id": "u13q1"}, {"type": "cloze", "prompt": "Completa con for o since. Rellena el hueco con UNA palabra.", "text": "I''ve lived here ___ 2019.", "answer": "since", "accepted": ["since"], "id": "u13q2"}, {"type": "cloze", "prompt": "Completa con for o since. Rellena el hueco con UNA palabra.", "text": "She has worked at the hospital ___ five years.", "answer": "for", "accepted": ["for"], "id": "u13q3"}, {"type": "multiple_choice", "prompt": "¿Cuál es la forma correcta en negativa de \"used to\"?", "options": ["He didn''t use to drink tea.", "He didn''t used to drink tea.", "He didn''t using to drink tea."], "answer": "He didn''t use to drink tea.", "id": "u13q4"}, {"type": "cloze", "prompt": "Completa con la palabra que indica que algo pasó hace un momento (entre ''has'' y el participio). Rellena el hueco con UNA palabra.", "text": "The train has ___ arrived, so we can get on now.", "answer": "just", "accepted": ["just"], "id": "u13q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 14, 'B1', 'Trabajo, estudios y planes', 'Aprende a contar cuánto llevas en un trabajo o estudio, a hablar de planes ya decididos frente a decisiones del momento, y a plantear condiciones sobre tu futuro.', '[{"heading": "\"Llevo + tiempo\" = have been + -ing", "body": "El presente perfecto continuo une pasado y presente: la acción empezó antes y sigue ahora. Se forma con have/has been + verbo en -ing. Usa for con la duración (for two years) y since con el punto de inicio (since 2022).", "bullets": ["I''ve been studying English for six months = llevo seis meses estudiando.", "for + duración; since + momento de inicio.", "He/She/It usa has been: She''s been working there.", "En español vale \"llevo/tengo + tiempo\"; en inglés NUNCA con have."]}, {"heading": "Planes: going to vs will", "body": "Usa be going to cuando el plan ya está decidido antes de hablar, o cuando hay evidencia visible. Usa will cuando decides en ese mismo momento, ofreces ayuda o haces una predicción u opinión sobre el futuro.", "bullets": ["Decidido antes: I''m going to look for a new job.", "Evidencia clara: Look at those clouds. It''s going to rain.", "Decisión ahora mismo: OK, I''ll call the office.", "Predicción u opinión: I think she''ll pass the exam."]}, {"heading": "If + presente, will + verbo", "body": "El primer condicional habla de futuro real y probable. En la parte con if va el presente simple, aunque el significado sea futuro; en la otra parte va will + verbo. Puedes invertir el orden sin cambiar el sentido.", "bullets": ["If I get the job, I''ll move to Madrid.", "En el primer condicional, tras if no se usa will.", "Orden libre: I''ll move to Madrid if I get the job.", "Sin coma cuando la frase empieza por la parte con will."]}]'::jsonb, '[{"en": "I''ve been working here for two years.", "es": "Llevo dos años trabajando aquí.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/fd134e42-cb09-5bef-bc22-f3a229d1be8e.mp3"}, {"en": "I''m going to look for a new job in September.", "es": "Voy a buscar un trabajo nuevo en septiembre.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e2adc30d-7064-55f1-93a1-a9f36c5d6bf2.mp3"}, {"en": "Don''t worry, I''ll help you with the report.", "es": "No te preocupes, te ayudo con el informe.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/9cf73b82-bad7-5c5b-8abb-d4a72a1a25e0.mp3"}, {"en": "If I get the scholarship, I''ll move to Canada.", "es": "Si consigo la beca, me mudaré a Canadá.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/abc69c16-f70d-52fc-a27e-8a351d4b8190.mp3"}]'::jsonb, '[{"title": "\"Si llueve\" no es \"If it will rain\"", "body": "En el primer condicional, la parte con if va en presente simple aunque hable del futuro. Error típico: If it will rain, we will stay home. Correcto: If it rains, we will stay home."}, {"title": "\"Llevo dos años aquí\" no es \"I have two years here\"", "body": "El español usa tener/llevar, pero el inglés usa have been + -ing con for. Error típico: I have two years working here. Correcto: I''ve been working here for two years."}, {"title": "going to para lo ya decidido", "body": "Si el plan estaba decidido antes de hablar, no uses will. Error típico: I already enrolled, so I will study medicine. Correcto: I already enrolled, so I''m going to study medicine."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cómo dices \"Llevo seis meses estudiando inglés\"?", "options": ["I''ve been studying English for six months.", "I study English for six months.", "I am studying English since six months."], "answer": "I''ve been studying English for six months.", "id": "u14q1"}, {"type": "cloze", "prompt": "Completa con for o since: la duración es \"tres años\".", "text": "She has been teaching at that school ___ three years.", "answer": "for", "accepted": ["for"], "id": "u14q2"}, {"type": "cloze", "prompt": "Completa con la estructura ''be going to'' (plan ya decidido).", "text": "I''ve already bought my ticket. I''m ___ to study in Dublin in July.", "answer": "going", "accepted": ["going"], "id": "u14q3"}, {"type": "cloze", "prompt": "Primer condicional: completa la parte con if usando el presente del verbo pass.", "text": "If you ___ the exam, you''ll get the job.", "answer": "pass", "accepted": ["pass"], "id": "u14q4"}, {"type": "multiple_choice", "prompt": "El teléfono suena en la oficina y decides contestar en ese mismo momento. ¿Qué dices?", "options": ["I''ll answer it.", "I''m going to answer it.", "I answer it."], "answer": "I''ll answer it.", "id": "u14q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
