  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 15, 'B1', 'Opiniones y acuerdos', 'Vas a dar tu opinión con fórmulas variadas y naturales, y a mostrar acuerdo o desacuerdo sin el error clásico de "I am agree".', '[{"heading": "Agree es un VERBO, no un adjetivo", "body": "En español \"estar de acuerdo\" lleva verbo + adjetivo, pero en inglés agree ya es el verbo. Por eso se conjuga solo y la negación se forma con do/does, como cualquier verbo normal.", "bullets": ["I agree. / She agrees with you.", "Negativo: I don''t agree o I disagree.", "Preposición: agree WITH somebody, agree ON something.", "Pregunta: Do you agree? (no \"Are you agree?\")."]}, {"heading": "Dar tu opinión más allá de I think", "body": "Repetir I think suena pobre en B1. Alterna registros: In my opinion abre la frase, I believe suena más firme, It seems to me suaviza, y If you ask me es coloquial. Todas van seguidas de una oración completa.", "bullets": ["In my opinion, prices are too high.", "I believe / I feel (that) we should wait.", "It seems to me that he''s right.", "Personally, I''d say it''s a mistake."]}, {"heading": "So do I / Neither do I: coincidir en corto", "body": "Para decir \"yo también / yo tampoco\" se repite el auxiliar de la frase anterior, no el verbo entero. So responde a frases afirmativas; Neither, a negativas. El orden es siempre auxiliar + sujeto (invertido).", "bullets": ["I love jazz. → So do I. (auxiliar do)", "She''s tired. → So am I. (auxiliar am)", "I don''t smoke. → Neither do I.", "Alternativa informal: Me too / Me neither."]}]'::jsonb, '[{"en": "In my opinion, the film was too long.", "es": "En mi opinión, la película fue demasiado larga.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ad52da26-784a-52e3-aa14-81f5a512acf7.mp3"}, {"en": "I don''t agree with Sara, but I understand her point.", "es": "No estoy de acuerdo con Sara, pero entiendo su postura.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/05a34410-5fab-5f9d-b7f1-da533095929c.mp3"}, {"en": "— I''ve never been to Japan. — Neither have I.", "es": "— Nunca he estado en Japón. — Yo tampoco.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/d7bf6353-4de1-5f3c-9f9b-57af70dbc765.mp3"}, {"en": "It seems to me that we should book the tickets today.", "es": "Me parece que deberíamos reservar los billetes hoy.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/202e0078-4be0-5070-988d-5c7b09229175.mp3"}]'::jsonb, '[{"title": "\"I am agree\" no existe", "body": "Agree ya significa \"estar de acuerdo\", así que no lleva be. Di I agree, I don''t agree o I disagree. Tampoco uses \"Are you agree?\": la pregunta correcta es Do you agree?"}, {"title": "El auxiliar de So/Neither debe copiar la frase anterior", "body": "No repitas siempre do. Si la frase lleva be, have o un modal, se repite ese: She''s happy → So am I. I can''t swim → Neither can I. Decir \"So do I\" ahí es un error."}, {"title": "Neither ya es negativo", "body": "Un error frecuente es \"Neither I don''t\" o \"Me neither don''t\". Neither carga la negación por sí solo: I don''t like coffee → Neither do I (nunca \"Neither don''t I\")."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta para decir \"no estoy de acuerdo contigo\".", "options": ["I am not agree with you.", "I don''t agree with you.", "I am disagree with you."], "answer": "I don''t agree with you.", "id": "u15q1"}, {"type": "cloze", "prompt": "Completa con el auxiliar correcto (una sola palabra). Frase afirmativa con el verbo love.", "text": "— I love jazz. — So ___ I.", "answer": "do", "accepted": ["do"], "id": "u15q2"}, {"type": "cloze", "prompt": "Completa con el auxiliar correcto (una sola palabra). Fíjate en que la frase anterior lleva el verbo be.", "text": "— I''m really tired today. — So ___ I.", "answer": "am", "accepted": ["am"], "id": "u15q3"}, {"type": "multiple_choice", "prompt": "Tu compañero dice: \"I don''t eat meat.\" Tú comes igual que él. ¿Cómo respondes?", "options": ["So do I.", "Neither do I.", "Neither I do."], "answer": "Neither do I.", "id": "u15q4"}, {"type": "multiple_choice", "prompt": "¿Cuál de estas frases para dar una opinión es correcta en inglés?", "options": ["In my opinion, this city is expensive.", "In my opinion is this city expensive.", "For my opinion, this city is expensive."], "answer": "In my opinion, this city is expensive.", "id": "u15q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
