  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 16, 'B1', 'Historias y viajes', 'Aprende a contar una historia o un viaje: montar la escena de fondo con el pasado continuo, cortarla con el pasado simple y describir a la gente y las cosas con who, which y that.', '[{"heading": "La escena de fondo y la interrupción", "body": "Para narrar, primero pintas la escena que ya estaba en marcha (was/were + -ing) y luego cuentas el hecho breve que la corta (pasado simple). Es la columna vertebral de cualquier anécdota de viaje.", "bullets": ["Acción larga de fondo: was/were + -ing.", "Acción breve que la interrumpe: pasado simple.", "Dos acciones largas a la vez: ambas en pasado continuo."]}, {"heading": "While y when: cuál va con cuál", "body": "While suele introducir la acción larga; when suele introducir la breve. La frase con while o when puede ir delante o detrás: si va delante, lleva coma. El orden no cambia el significado.", "bullets": ["While + pasado continuo: While I was packing…", "When + pasado simple: …when my phone rang.", "Coma solo si esa parte abre la frase.", "As funciona casi como while en un relato."]}, {"heading": "Who, which, that: describir gente y cosas", "body": "Usa who para personas y which para cosas o animales. That sirve para ambas en frases que identifican de cuál hablas. Así encadenas detalles sin cortar la historia en frases sueltas.", "bullets": ["Personas: the woman who / that sold the tickets.", "Cosas: the bus which / that broke down.", "No repitas el sujeto: the man who he helped es incorrecto.", "Where para lugares: the hostel where we stayed."]}]'::jsonb, '[{"en": "While we were waiting on the platform, the train arrived.", "es": "Mientras esperábamos en el andén, llegó el tren.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/efdd4948-6fec-5697-a6b6-a76416415a11.mp3"}, {"en": "I was reading my map when a stranger offered to help me.", "es": "Estaba leyendo mi mapa cuando un desconocido se ofreció a ayudarme.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ce427a59-59ee-5715-90e7-62fbdcbea87c.mp3"}, {"en": "The guide who took us to the lake spoke four languages.", "es": "El guía que nos llevó al lago hablaba cuatro idiomas.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/361b1c5b-1702-5447-8216-f91b1532f52c.mp3"}, {"en": "We finally found the little hotel that my sister had recommended.", "es": "Por fin encontramos el hotelito que mi hermana había recomendado.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/85f00e54-0fb7-521a-ac03-89f6c2c5e144.mp3"}]'::jsonb, '[{"title": "Usar el pasado simple para la escena de fondo", "body": "Para la escena de fondo de un relato, el continuo suena mucho más natural: ''While I was cooking, he arrived''. El pasado simple es gramatical, pero pierde el efecto de acción en marcha."}, {"title": "Repetir el sujeto después de who o that", "body": "El español permite \"el chico que él me ayudó\" en el habla, pero en inglés no: nunca \"the boy who he helped me\". Correcto: the boy who helped me."}, {"title": "Usar who para cosas o which para personas", "body": "Se oye \"the bus who was late\" o \"the woman which called me\". Correcto: the bus which/that was late; the woman who/that called me."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la opción correcta: la acción larga de fondo con while.", "options": ["While we were driving, we saw a beautiful castle.", "While we drove, we were seeing a beautiful castle.", "While we drive, we saw a beautiful castle."], "answer": "While we were driving, we saw a beautiful castle.", "id": "u16q1"}, {"type": "cloze", "prompt": "Completa con el pasado continuo del verbo wait.", "text": "I ___ for my flight when they announced the delay.", "answer": "was waiting", "accepted": ["was waiting", "had been waiting"], "id": "u16q2"}, {"type": "cloze", "prompt": "Completa con el relativo adecuado para una persona.", "text": "The man ___ helped us with our bags was very kind.", "answer": "who", "accepted": ["who", "that"], "id": "u16q3"}, {"type": "multiple_choice", "prompt": "Elige la frase correcta para hablar de una cosa.", "options": ["The camera which I bought in Rome still works.", "The camera who I bought in Rome still works.", "The camera which I bought it in Rome still works."], "answer": "The camera which I bought in Rome still works.", "id": "u16q4"}, {"type": "cloze", "prompt": "Completa con when o while según la acción breve que interrumpe.", "text": "We were walking through the market ___ it started to rain.", "answer": "when", "accepted": ["when"], "id": "u16q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 17, 'B1', 'Problemas y soluciones', 'Aprende a describir un problema y proponer la solución: obligaciones con must y have to, consejos con should, y hechos que siempre se cumplen con el condicional 0.', '[{"heading": "Must y have to: la obligación", "body": "Las dos expresan obligación y muchas veces se pueden intercambiar. La diferencia es de matiz: must suena a decisión propia o a norma escrita; have to suena a regla que viene de fuera. En pasado solo existe had to.", "bullets": ["must: obligación que sientes tú (I must fix this today).", "have to: regla externa (I have to wear a helmet at work).", "mustn''t = está prohibido; don''t have to = no es necesario.", "Pasado y futuro: had to, will have to (no \"musted\")."]}, {"heading": "Should: aconsejar sin imponer", "body": "Should y shouldn''t dan consejos y opiniones: es lo recomendable, no lo obligatorio. Le sigue el infinitivo sin to. Para preguntar consejo, invierte el orden: Should I call them?", "bullets": ["should + verbo base: You should restart the computer.", "shouldn''t: You shouldn''t ignore that noise.", "Más suave que must; deja libertad a la otra persona.", "Nunca \"should to\" ni \"should calls\"."]}, {"heading": "Condicional 0: causa y efecto", "body": "If + presente simple, presente simple. Sirve para verdades generales y resultados automáticos: siempre que pasa A, pasa B. No habla del futuro; para eso usarías el primer condicional (will).", "bullets": ["If you press this button, the machine stops.", "Puedes cambiar if por when con el mismo sentido.", "Las dos partes en presente: nunca \"if it will rain\".", "El orden es libre: The machine stops if you press this."]}]'::jsonb, '[{"en": "I have to leave now because the office closes at six.", "es": "Tengo que irme ya porque la oficina cierra a las seis.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e7d7bc9a-a030-5164-bbdc-4a428940f768.mp3"}, {"en": "You mustn''t open that box, but you don''t have to move it.", "es": "No debes abrir esa caja, pero no hace falta que la muevas.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ad0d25a1-28d8-525e-b0d4-8378a8b4205a.mp3"}, {"en": "You should call the technician before the problem gets worse.", "es": "Deberías llamar al técnico antes de que el problema empeore.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7e3da96f-d350-5458-a2ec-635efbb2203c.mp3"}, {"en": "If the screen freezes, I restart the laptop.", "es": "Si la pantalla se congela, reinicio el portátil.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/f977d616-fce6-5936-8145-4e687e4d0fc0.mp3"}]'::jsonb, '[{"title": "mustn''t no es \"no hace falta\"", "body": "\"No tienes que pagar\" (no es necesario) es You don''t have to pay. Si dices You mustn''t pay, estás diciendo que está prohibido pagar. Es el error más caro de esta unidad."}, {"title": "Should to / must to", "body": "Los modales van con el verbo desnudo. Se dice You should ask for help y We must check the cables, no \"should to ask\" ni \"must to check\"."}, {"title": "If + will en el condicional 0", "body": "Un hispanohablante traduce \"si el agua hierve\" con futuro. En inglés las dos mitades van en presente: If water boils, it turns into steam. Nunca \"If water will boil\"."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "El sábado no trabajas: ir a la oficina no es necesario. Elige la frase correcta.", "options": ["You don''t have to go to the office on Saturday.", "You mustn''t go to the office on Saturday.", "You shouldn''t to go to the office on Saturday."], "answer": "You don''t have to go to the office on Saturday.", "id": "u17q1"}, {"type": "multiple_choice", "prompt": "Tu amigo tiene un problema con el móvil y le das un consejo, no una orden. ¿Qué le dices?", "options": ["You should update the app.", "You should to update the app.", "You should updating the app."], "answer": "You should update the app.", "id": "u17q2"}, {"type": "cloze", "prompt": "Condicional 0: completa con el presente del verbo boil.", "text": "If you heat water to 100 degrees, it ___.", "answer": "boils", "accepted": ["boils"], "id": "u17q3"}, {"type": "cloze", "prompt": "Prohibición: la señal dice que está prohibido tocar los cables. Usa la forma negativa de must.", "text": "You ___ touch these cables. It''s dangerous.", "answer": "mustn''t", "accepted": ["mustn''t", "must not"], "id": "u17q4"}, {"type": "cloze", "prompt": "Obligación externa en pasado: la empresa nos obligó a volver. Usa have to en pasado.", "text": "The system crashed, so we ___ to work all night.", "answer": "had", "accepted": ["had"], "id": "u17q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 18, 'B1', 'Cultura, medios y futuro', 'Aprende a imaginar situaciones hipotéticas, comparar con naturalidad y usar la voz pasiva típica de los medios.', '[{"heading": "Imaginar el futuro: el segundo condicional", "body": "Para situaciones imaginarias o poco probables usamos: if + pasado simple, would + verbo. El pasado aquí no habla del pasado: marca distancia de la realidad. Sirve para soñar, especular sobre el futuro y dar consejos.", "bullets": ["If I had a robot, I would read more books.", "Con \"I/he/she\": \"If I were you\" es lo recomendado; \"was\" también se oye.", "Consejo típico: \"If I were you, I''d study film.\"", "En la parte con \"would\" nunca ponemos otro \"would\"."]}, {"heading": "Comparar culturas: as + adjetivo + as", "body": "Para decir que dos cosas son iguales usamos as + adjetivo + as. Si no son iguales, añadimos not delante. El adjetivo va siempre en forma base, sin -er ni more.", "bullets": ["The book is as good as the film.", "This series isn''t as popular as the original.", "Nunca: \"as better as\" ni \"as more popular as\".", "También con adverbios: \"She sings as well as her sister.\""]}, {"heading": "Noticias y medios: la pasiva (be + participio)", "body": "Cuando importa más la acción que el autor, usamos be + participio. Es el estilo típico de noticias, cine y televisión. Si queremos nombrar al autor, añadimos by.", "bullets": ["The film was directed by a young woman.", "El verbo be marca el tiempo: is / was / will be.", "Millions of people are informed online every day.", "Si el autor es obvio o desconocido, no hace falta \"by\"."]}]'::jsonb, '[{"en": "If I had more time, I would learn the guitar.", "es": "Si tuviera más tiempo, aprendería a tocar la guitarra.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/a0ad1bed-5ff3-5355-89b0-61edb8cf4f0d.mp3"}, {"en": "If I were you, I would watch the documentary in English.", "es": "Si yo fuera tú, vería el documental en inglés.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ca365604-b51a-526f-8dd8-77e53d7cc4e6.mp3"}, {"en": "Streaming is not as expensive as the cinema.", "es": "El streaming no es tan caro como el cine.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ef373fde-aef9-546c-93e2-b6c94003b25b.mp3"}, {"en": "The news was published this morning by a local newspaper.", "es": "La noticia fue publicada esta mañana por un periódico local.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e794ba86-d3fb-5b4c-8e19-5480cf29ab4c.mp3"}]'::jsonb, '[{"title": "\"If I would have...\" en la condición", "body": "El español \"si tuviera\" empuja a decir \"If I would have time\". En inglés, would va solo en la otra parte: \"If I had time, I would travel.\""}, {"title": "\"as cheaper as\" / \"as more popular as\"", "body": "Entre as ... as el adjetivo va en forma base: \"as cheap as\", \"as popular as\". El comparativo (cheaper, more popular) pide than: \"cheaper than\"."}, {"title": "Olvidar el verbo be en la pasiva", "body": "\"The series filmed in Ireland\" significa que la serie filmó algo. Lo correcto es \"The series was filmed in Ireland\": be + participio."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la opción correcta: consejo con segundo condicional.", "options": ["If I were you, I would read the reviews first.", "If I would be you, I read the reviews first.", "If I am you, I would read the reviews first."], "answer": "If I were you, I would read the reviews first.", "id": "u18q1"}, {"type": "cloze", "prompt": "Completa con la pasiva en pasado del verbo film.", "text": "The series ___ filmed in Ireland.", "answer": "was", "accepted": ["was"], "id": "u18q2"}, {"type": "cloze", "prompt": "Completa la comparación de igualdad. Usa una sola palabra.", "text": "The documentary is as interesting ___ the film.", "answer": "as", "accepted": ["as"], "id": "u18q3"}, {"type": "multiple_choice", "prompt": "¿Qué frase compara correctamente dos plataformas?", "options": ["This app isn''t as popular as the old one.", "This app isn''t as more popular as the old one.", "This app isn''t as popularer than the old one."], "answer": "This app isn''t as popular as the old one.", "id": "u18q4"}, {"type": "cloze", "prompt": "Completa el segundo condicional con la forma correcta del verbo have.", "text": "If she ___ a bigger screen, she would watch more films at home.", "answer": "had", "accepted": ["had"], "id": "u18q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 19, 'B2', 'Logros y trayectoria', 'Aprende a contar tu trayectoria profesional con precisión: qué habías logrado antes de cierto momento y cuánto tiempo llevas haciendo algo.', '[{"heading": "Past perfect: el pasado antes del pasado", "body": "Usa had + participio para el hecho ANTERIOR cuando ya estás narrando en pasado. Ordena tu trayectoria: primero lo que ya habías conseguido, después el momento que cuentas. Es la forma natural de explicar tu recorrido en una entrevista.", "bullets": ["had + participio, igual para todas las personas.", "Marcadores típicos: by 2020, before, already, when.", "Contraste: When I applied, I had led three teams.", "Negativo e interrogativo: hadn''t finished / Had you worked...?"]}, {"heading": "Present perfect continuous: llevo X tiempo haciendo algo", "body": "Para una actividad que empezó en el pasado y sigue hoy, usa have/has been + -ing. Es lo que en español dices con «llevo... trabajando». Ideal para presentar tu experiencia actual, no un logro cerrado.", "bullets": ["I have been working here for six years.", "Tercera persona: She has been managing the team.", "Enfoca la duración y la continuidad de la actividad.", "Para un resultado contable, mejor el perfecto simple: I''ve written three reports."]}, {"heading": "for vs since", "body": "For introduce la duración completa: for two years, for a long time. Since introduce el punto de inicio: since 2019, since I graduated. Elegir mal aquí es el error más visible al hablar de trayectoria.", "bullets": ["for + periodo: for six months, for a decade.", "since + momento concreto: since March, since my promotion.", "since + oración en pasado simple: since I joined the company.", "How long...? pide una de las dos respuestas."]}]'::jsonb, '[{"en": "By 2020, she had already launched two companies.", "es": "Para 2020, ya había lanzado dos empresas.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/1b5790c5-e86f-566b-b479-871326cc3a8d.mp3"}, {"en": "I have been leading the design team since 2019.", "es": "Llevo dirigiendo el equipo de diseño desde 2019.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/d6110625-038d-543d-881f-d784b883b9cd.mp3"}, {"en": "Before he moved to Berlin, he had worked in three countries.", "es": "Antes de mudarse a Berlín, había trabajado en tres países.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/d619cd3e-ad64-55c2-baa3-254b4a7ec229.mp3"}, {"en": "They have been negotiating the contract for eight weeks.", "es": "Llevan ocho semanas negociando el contrato.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/2be86bd2-d43e-561e-aec7-8ffb53b69c85.mp3"}]'::jsonb, '[{"title": "Traducir «llevo X años» con «I have X years»", "body": "El calco de «llevo cinco años trabajando aquí» suena raro en inglés. No digas I have five years working here; di I have been working here for five years."}, {"title": "Confundir for y since", "body": "Since marca el inicio, no la duración. No digas since three years; di for three years, o bien since 2021 si nombras el punto de partida."}, {"title": "Usar pasado simple donde hace falta past perfect", "body": "Si un hecho es anterior a otro pasado, márcalo. En vez de When I arrived, the meeting already started, di When I arrived, the meeting had already started (en inglés informal americano se oye el pasado simple, pero en un examen el past perfect marca la anterioridad)."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la opción correcta: «Llevo ocho meses dirigiendo este proyecto (y sigo).»", "options": ["I have been running this project for eight months.", "I have been running this project since eight months.", "I run this project since eight months ago."], "answer": "I have been running this project for eight months.", "id": "u19q1"}, {"type": "cloze", "prompt": "Completa con el past perfect del verbo «start» (una sola palabra en el hueco).", "text": "When I arrived, the meeting ___ already started.", "answer": "had", "accepted": ["had", "''d"], "id": "u19q2"}, {"type": "multiple_choice", "prompt": "¿Cuál describe correctamente un logro anterior a otro momento pasado?", "options": ["Before she joined us, she had won two industry awards.", "Before she joined us, she has won two industry awards.", "Before she joined us, she was winning two industry awards."], "answer": "Before she joined us, she had won two industry awards.", "id": "u19q3"}, {"type": "cloze", "prompt": "Completa con «for» o «since»: la frase nombra el momento en que empezó.", "text": "He has been teaching at this university ___ 2015.", "answer": "since", "accepted": ["since"], "id": "u19q4"}, {"type": "cloze", "prompt": "Completa con «for» o «since»: la frase indica la duración total.", "text": "We have been working on this proposal ___ three weeks.", "answer": "for", "accepted": ["for"], "id": "u19q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 20, 'B2', 'Lo que dijeron', 'Vas a contar lo que otra persona dijo o preguntó: mover el tiempo verbal un paso atrás, ordenar las preguntas indirectas como afirmaciones y elegir bien entre say y tell.', '[{"heading": "El tiempo retrocede un paso", "body": "Si el verbo introductor va en pasado (said, told), el verbo de dentro suele retroceder un paso. Es el patrón por defecto y el que se espera en un examen. No lo apliques si lo dicho sigue siendo verdad ahora: ahí puedes dejar el presente.", "bullets": ["am/is/are → was/were; do/does → did.", "Pasado simple y present perfect → past perfect (had done).", "will → would; can → could; must → had to (o queda must)", "Sigue vigente: \"She said she lives in Madrid\" también vale."]}, {"heading": "Preguntas indirectas: orden de afirmación", "body": "Al contar una pregunta, esta deja de comportarse como pregunta: sujeto antes del verbo, sin do/does/did y sin signo de interrogación. En las de sí o no metes if o whether; en las demás repites la palabra interrogativa.", "bullets": ["\"Where do you live?\" → He asked where I lived.", "Nada de do/does/did dentro de la pregunta indirecta.", "Sí/no → if o whether; ambas son correctas.", "El punto final sustituye al signo de interrogación."]}, {"heading": "Say y tell no se reparten igual", "body": "Tell pide la persona pegada al verbo: tell me, tell her, told us. Say no la lleva directamente; si quieres mencionarla, necesitas to. Con órdenes o consejos, ambos van seguidos de to + infinitivo.", "bullets": ["tell + persona: She told me she was leaving.", "say sin persona: She said she was leaving.", "Con persona, say exige to: She said to me...", "Órdenes: He told me to wait. (no \"said me\")"]}]'::jsonb, '[{"en": "She said she was tired.", "es": "Dijo que estaba cansada.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/afc91490-7d3b-51c3-8304-1a15cc906b8e.mp3"}, {"en": "He told me he had already sent the report.", "es": "Me dijo que ya había enviado el informe.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/8df3dbf6-419f-5e54-96d0-15449cb37d0d.mp3"}, {"en": "They asked me where I worked.", "es": "Me preguntaron dónde trabajaba.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7d02b605-1728-5889-bf6c-b740aff8a15f.mp3"}, {"en": "The manager asked whether we would accept the offer.", "es": "El gerente preguntó si aceptaríamos la oferta.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/c87d3223-65a0-5e04-9382-43040eb4a729.mp3"}]'::jsonb, '[{"title": "\"He said me\" no existe", "body": "El español dice \"me dijo\" con un solo verbo, y muchos lo traducen como \"He said me that...\". Say no admite la persona pegada: usa \"He told me that...\" o, si insistes en say, \"He said to me that...\"."}, {"title": "Mantener el orden de pregunta al contarla", "body": "Suena natural decir \"She asked me where do I live\", pero es incorrecto. La pregunta indirecta se ordena como una afirmación y sin auxiliar: \"She asked me where I lived\"."}, {"title": "Olvidar mover will y el pasado", "body": "En un examen, el retroceso es lo seguro: ''She said she had seen it''. En el habla real ''She said she saw it'' también es correcto y muy frecuente."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta del estilo indirecto: \"I am busy,\" she said. → She said she ___ busy.", "options": ["was", "is being", "has been"], "answer": "was", "id": "u20q1"}, {"type": "multiple_choice", "prompt": "¿Cuál es la versión correcta de la pregunta indirecta?", "options": ["He asked me where I worked.", "He asked me where did I work.", "He asked me where do I work."], "answer": "He asked me where I worked.", "id": "u20q2"}, {"type": "cloze", "prompt": "Completa con el verbo adecuado (say o tell) en pasado.", "text": "She ___ me that the meeting had been cancelled.", "answer": "told", "accepted": ["told"], "id": "u20q3"}, {"type": "cloze", "prompt": "Pasa la pregunta a estilo indirecto: \"Where do you live?\" he asked.", "text": "He asked me where I ___.", "answer": "lived", "accepted": ["lived", "live"], "id": "u20q4"}, {"type": "cloze", "prompt": "Completa la pregunta indirecta de sí/no (dos palabras son posibles).", "text": "They asked ___ we wanted more time.", "answer": "if", "accepted": ["if", "whether"], "id": "u20q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 21, 'B2', 'Cómo se hace y las noticias', 'Aprenderás a decir que otra persona hace algo por ti (have/get something done) y a contar hechos como lo hacen las noticias, con la pasiva y el agente ''by''.', '[{"heading": "Have / get something done: no lo haces tú", "body": "Usa have + objeto + participio cuando encargas un servicio: I had my hair cut. Get es igual pero más informal: I got my hair cut. El objeto va en medio, siempre antes del participio.", "bullets": ["Estructura: have/get + cosa + participio pasado.", "I cut my hair = yo mismo; I had it cut = un profesional.", "También para sucesos negativos: They had their car stolen.", "Get es más coloquial; have, más neutro."]}, {"heading": "La pasiva en las noticias: be + participio", "body": "El titular pone el hecho primero: A new bridge was opened yesterday. Cambia solo el verbo be según el tiempo; el participio no se mueve. Es la voz habitual de informes, noticias y textos formales.", "bullets": ["Presente: is/are built. Pasado: was/were built.", "Perfecto: has/have been built. Futuro: will be built.", "Con modal: must be checked, can be repaired.", "El verbo be concuerda con el sujeto, no con el agente."]}, {"heading": "El agente con ''by'': solo si aporta", "body": "Añade by + persona cuando saber quién lo hizo es relevante o sorprendente. Si es obvio, desconocido o irrelevante, se omite: My wallet was stolen. En las noticias se omite muchísimo más de lo que se pone.", "bullets": ["Ponlo si importa: The law was passed by parliament.", "Omítelo si es obvio: He was arrested (por la policía).", "Con have/get done, el agente rara vez aparece.", "By marca el autor; with marca el instrumento."]}]'::jsonb, '[{"en": "I had my car repaired last week.", "es": "Me repararon el coche la semana pasada.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/5ae8ada3-2541-5fda-8312-9fd1d788c6c0.mp3"}, {"en": "She got her passport renewed before the trip.", "es": "Se renovó el pasaporte (se lo renovaron) antes del viaje.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/880e327a-a02d-590f-bd1a-bc85c1bfaca2.mp3"}, {"en": "Three people have been rescued from the river.", "es": "Tres personas han sido rescatadas del río.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/53122b28-ce55-5c0e-9408-e8764cd8f299.mp3"}, {"en": "The report will be published by the government next month.", "es": "El informe será publicado por el gobierno el mes que viene.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/94600c8c-9398-599d-807e-b6c11d813cf3.mp3"}]'::jsonb, '[{"title": "Poner el participio antes del objeto", "body": "No digas ''I had repaired my car'' si quieres decir que te lo repararon: eso significa que ya lo habías reparado tú. El orden correcto es I had my car repaired."}, {"title": "Traducir el ''se'' impersonal con un reflexivo", "body": "''Se construyó el puente en 1890'' no es ''The bridge built itself''. En inglés se usa la pasiva: The bridge was built in 1890."}, {"title": "Olvidar el verbo ''be'' en la pasiva", "body": "El participio solo no basta: ''The house sold last year'' cambia el sentido. Di The house was sold last year. Sin be no hay pasiva."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la frase que significa que un mecánico le arregló el coche, no él mismo.", "options": ["He had his car fixed yesterday.", "He had fixed his car yesterday.", "He was fixing his car yesterday."], "answer": "He had his car fixed yesterday.", "id": "u21q1"}, {"type": "cloze", "prompt": "Completa la pasiva con el verbo ''be'' en pasado simple.", "text": "The bridge ___ built in 1890.", "answer": "was", "accepted": ["was"], "id": "u21q2"}, {"type": "cloze", "prompt": "Completa con el verbo que falta para formar la pasiva en presente perfecto.", "text": "Two suspects have ___ arrested this morning.", "answer": "been", "accepted": ["been"], "id": "u21q3"}, {"type": "multiple_choice", "prompt": "¿En cuál de estas frases es realmente útil añadir el agente con ''by''?", "options": ["The new stadium was designed by a Japanese architect.", "My bike was stolen by a thief.", "The thief was arrested by a police officer."], "answer": "The new stadium was designed by a Japanese architect.", "id": "u21q4"}, {"type": "cloze", "prompt": "Completa para decir que otra persona le corta el pelo a ella cada mes (verbo en presente simple, tercera persona).", "text": "She ___ her hair cut every month.", "answer": "has", "accepted": ["has", "gets"], "id": "u21q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 22, 'B2', 'Hipótesis y arrepentimientos', 'Aquí vas a dominar el tercer condicional para hablar de un pasado que no ocurrió, y los condicionales mixtos para conectar una condición pasada con un resultado presente.', '[{"heading": "Tercer condicional: el pasado que no fue", "body": "Sirve para imaginar un pasado distinto: la condición no se cumplió y el resultado tampoco. Es la estructura del arrepentimiento y de la crítica. Se forma con had + participio en la condición, y would have + participio en el resultado.", "bullets": ["If + had + participio, would have + participio.", "Los dos hechos son irreales: no pasaron.", "Puedes invertir el orden sin coma: I would have called if I had known.", "Contracciones naturales: If I''d known…, we''d have won."]}, {"heading": "Nunca ''would'' dentro del if", "body": "En inglés estándar, la cláusula del if no lleva would. La condición usa siempre had + participio. En español decimos ''hubiera'' en las dos partes, y de ahí sale el error más repetido de todos.", "bullets": ["Correcto: If I had studied, I would have passed.", "Incorrecto: If I would have studied…", "Sí puedes negar: If she hadn''t left, we''d have finished.", "Alternativa formal sin if: Had I known, I would have called."]}, {"heading": "Condicionales mixtos: pasado que aún pesa", "body": "Cuando una condición pasada tiene consecuencias hoy, mezclas los tiempos: had + participio en la condición, pero would + infinitivo en el resultado. Palabras como now o today aclaran que hablas del presente.", "bullets": ["If I had studied medicine, I would be a doctor now.", "La condición mira al pasado; el resultado, al presente.", "Sin have en el resultado: would be, no would have been.", "Marcadores útiles: now, today, still."]}]'::jsonb, '[{"en": "If I had known about the meeting, I would have called you.", "es": "Si hubiera sabido lo de la reunión, te habría llamado.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/5df2ac80-61d6-5695-9fa8-90f696bd8fe1.mp3"}, {"en": "She wouldn''t have missed the flight if she had left home earlier.", "es": "No habría perdido el vuelo si hubiera salido de casa más temprano.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/a6e300d0-f35a-5356-822c-602b45af8ddb.mp3"}, {"en": "If we hadn''t taken that job, we would still be living in Madrid.", "es": "Si no hubiéramos aceptado ese trabajo, todavía estaríamos viviendo en Madrid.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/239e748e-1989-5903-9960-f84b8938c8cb.mp3"}, {"en": "Had they warned us, the whole problem would have been avoided.", "es": "Si nos hubieran avisado, todo el problema se habría evitado.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/844ef7e4-22c0-5909-a298-6e55b900f603.mp3"}]'::jsonb, '[{"title": "''would'' colado en la cláusula del if", "body": "El español repite ''hubiera'' en las dos partes y arrastramos ese eco al inglés. Decimos «If I would have seen it…», pero el inglés estándar exige «If I had seen it, I would have told you». En el if, solo had + participio."}, {"title": "Usar el pasado simple en vez del pluscuamperfecto", "body": "«If I knew that yesterday, I would have gone» no funciona para un pasado irreal. La condición necesita had: «If I had known that yesterday, I would have gone»."}, {"title": "Meter ''have'' en el resultado de un condicional mixto", "body": "Si el resultado es presente, no lleva have. «If I had saved money, I would have been rich now» suena mal; lo natural es «If I had saved money, I would be rich now»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la opción correcta: ___ about the delay, we would have taken the earlier train.", "options": ["If we had known", "If we would have known", "If we know"], "answer": "If we had known", "id": "u22q1"}, {"type": "cloze", "prompt": "Completa con UNA palabra (tercer condicional, resultado irreal en pasado):", "text": "If we had left earlier, we ___ have caught the train.", "answer": "would", "accepted": ["would", "''d", "could", "might"], "id": "u22q2"}, {"type": "cloze", "prompt": "Completa con UNA palabra: la condición del if necesita el pluscuamperfecto.", "text": "If she ___ studied harder, she would have passed the exam.", "answer": "had", "accepted": ["had", "''d"], "id": "u22q3"}, {"type": "multiple_choice", "prompt": "Condicional mixto. Elige el resultado presente correcto: If I had accepted that offer, I ___ in London now.", "options": ["would be living", "would have lived", "will be living"], "answer": "would be living", "id": "u22q4"}, {"type": "multiple_choice", "prompt": "¿Cuál de estas frases es INCORRECTA en inglés estándar?", "options": ["If I would have seen you, I would have said hello.", "If I had seen you, I would have said hello.", "Had I seen you, I would have said hello."], "answer": "If I would have seen you, I would have said hello.", "id": "u22q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 23, 'B2', 'Personas, lugares y definiciones', 'Aprende a describir y definir con precisión: cuándo la relativa identifica de cuál hablas y cuándo solo añade un dato extra.', '[{"heading": "Especificativas: identifican, sin comas", "body": "La relativa especificativa dice DE CUÁL hablas. Si la quitas, la frase pierde información esencial. No lleva comas y admite ''that''.", "bullets": ["The woman who called you is my boss.", "who/that para personas; which/that para cosas", "Si el relativo es objeto, puedes omitirlo: the book (that) I read"]}, {"heading": "Explicativas: dato extra, entre comas", "body": "La explicativa añade información prescindible sobre algo que ya está identificado. Va entre comas y NO admite ''that''.", "bullets": ["My sister, who lives in Rome, is a nurse.", "Con nombres propios suele ser explicativa", "Entre comas nunca that; sí who, which (y whose, where)"]}, {"heading": "Where, whose y el falso ''what''", "body": "''Where'' sustituye a in/at which para lugares y ''whose'' indica posesión. El ''que'' relativo del español nunca se traduce como ''what''.", "bullets": ["the city where I was born (= in which)", "the man whose car was stolen", "NO: the man what came. SÍ: the man who came"]}]'::jsonb, '[{"en": "The woman who called you is my new boss.", "es": "La mujer que te llamó es mi nueva jefa.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/16d740b2-7f9e-5b6d-b043-65ee088a1839.mp3"}, {"en": "My sister, who lives in Rome, is a nurse.", "es": "Mi hermana, que vive en Roma, es enfermera.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/924c10d5-8419-59e5-91cf-d53c8157e447.mp3"}, {"en": "That''s the café where we first met.", "es": "Ese es el café donde nos conocimos.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/62f46f75-421d-56aa-9d32-83ead0a005a0.mp3"}, {"en": "I know a designer whose work is famous.", "es": "Conozco a un diseñador cuyo trabajo es famoso.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/93a18fed-bf03-5301-9c32-1d36351fa7ea.mp3"}]'::jsonb, '[{"title": "''What'' no es pronombre relativo", "body": "''The man what came'' es incorrecto. Usa ''who'' para personas y ''which/that'' para cosas: ''The man who came''."}, {"title": "''That'' no cabe entre comas", "body": "En las explicativas solo valen ''who'' y ''which''. Di ''My car, which is old, still works'', no ''..., that is old''."}, {"title": "Las comas cambian el sentido", "body": "''The students, who passed, celebrated'' implica que TODOS aprobaron. Sin comas, solo celebraron los que aprobaron."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cuál es correcta?", "options": ["The man who fixed my laptop is here.", "The man what fixed my laptop is here.", "The man which fixed my laptop is here."], "answer": "The man who fixed my laptop is here.", "id": "u23q1"}, {"type": "multiple_choice", "prompt": "Elige el relativo válido en la explicativa: ''My laptop, ___ cost 900 euros, broke yesterday.''", "options": ["which", "that", "what"], "answer": "which", "id": "u23q2"}, {"type": "cloze", "prompt": "Completa con UNA palabra (lugar).", "text": "That''s the restaurant ___ we had dinner.", "answer": "where", "accepted": ["where"], "id": "u23q3"}, {"type": "cloze", "prompt": "Completa con UNA palabra (posesión).", "text": "She''s the author ___ novel won the prize.", "answer": "whose", "accepted": ["whose"], "id": "u23q4"}, {"type": "cloze", "prompt": "Completa con UNA palabra el relativo de persona (especificativa).", "text": "The engineer ___ designed the bridge is from Peru.", "answer": "who", "accepted": ["who", "that"], "id": "u23q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 24, 'B2', 'Deducciones y debate', 'Aprende a razonar en voz alta sobre el pasado: decir qué es seguro, qué es posible y qué es imposible que ocurriera.', '[{"heading": "Deducir el pasado: modal + have + participio", "body": "Para conjeturar sobre algo ya ocurrido usas un modal seguido de ''have'' y el participio. El modal marca cuánta seguridad tienes.", "bullets": ["must have + participio: estoy casi seguro de que sí", "might / may / could have: es posible, no lo sé", "can''t / couldn''t have: es imposible que ocurriera"]}, {"heading": "Para lo imposible, can''t have", "body": "La negación de una deducción se hace con ''can''t have'' o ''couldn''t have''. ''Mustn''t'' expresa prohibición, no imposibilidad.", "bullets": ["She can''t have seen us; she was asleep.", "You mustn''t smoke here = prohibido, no deducción", "Tras ''have'' siempre participio: gone, no went"]}, {"heading": "Al oírlo suena ''must''ve''", "body": "En el habla natural ''must have'' se contrae en ''must''ve'', que suena casi como ''must of''. Es solo pronunciación: se escribe ''have''.", "bullets": ["Escrito: must have left. Hablado: must''ve left", "''Must of'' es un error de escritura muy frecuente", "Igual con could''ve, might''ve y can''t have"]}]'::jsonb, '[{"en": "She must have forgotten the meeting.", "es": "Seguro que se olvidó de la reunión.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/d80375a0-9172-5b18-856e-f378e74b6982.mp3"}, {"en": "They might have missed the last train.", "es": "Puede que hayan perdido el último tren.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/3881f2c6-501c-5636-aad0-fe9c0b5368ef.mp3"}, {"en": "He can''t have finished already; he just started.", "es": "Es imposible que haya terminado ya; acaba de empezar.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/24e13827-e1de-5f0b-b404-3c86d4b37758.mp3"}, {"en": "Someone must have left the door open.", "es": "Alguien debió de dejar la puerta abierta.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/bbc63fcc-a73e-5057-9cf9-fb8581a38ef4.mp3"}]'::jsonb, '[{"title": "''Mustn''t have'' no sirve para deducir", "body": "Para lo imposible usa ''can''t have'' o ''couldn''t have''. ''She mustn''t have seen us'' no es inglés estándar; di ''She can''t have seen us''."}, {"title": "''Must of'' no existe", "body": "Aunque al oído suene así, siempre se escribe ''must have'' (o ''must''ve'' en registro informal)."}, {"title": "Después de ''have'', participio", "body": "Di ''might have gone'', nunca ''might have went''. El participio no cambia con el modal."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "''Es imposible que lo supiera''. ¿Cuál es correcta?", "options": ["He can''t have known.", "He mustn''t have known.", "He doesn''t must know."], "answer": "He can''t have known.", "id": "u24q1"}, {"type": "multiple_choice", "prompt": "Elige la escritura correcta.", "options": ["She must have left early.", "She must of left early.", "She must has left early."], "answer": "She must have left early.", "id": "u24q2"}, {"type": "cloze", "prompt": "Completa con UNA palabra: deducción casi segura.", "text": "The lights are off and the car is gone. They ___ have gone home.", "answer": "must", "accepted": ["must"], "id": "u24q3"}, {"type": "cloze", "prompt": "Completa la deducción: es imposible que lo hiciera.", "text": "He ___ have taken my keys; they''re here in my bag.", "answer": "can''t", "accepted": ["can''t", "cannot", "can not", "couldn''t", "could not"], "id": "u24q4"}, {"type": "cloze", "prompt": "Completa con el participio del verbo ''go''.", "text": "They might have ___ to the beach.", "answer": "gone", "accepted": ["gone"], "id": "u24q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
